#include <stdio.h>

int main() {
    int num1, num2, sum;

    printf("Enter two integers: ");
    // Reading user input and storing it in variables
    scanf("%d %d", &num1, &num2);

    // Calculating the sum using the '+' operator
    sum = num1 + num2;

    // Displaying the result
    printf("The sum of %d and %d is: %d\n", num1, num2, sum);

    return 0;
}
